import React, { useState, useEffect, useRef, useCallback } from "react";
import io from "socket.io-client";
import { useAuth } from "./AuthProvider";
import Header from "./Header";
import { useNavigate, useLocation } from "react-router-dom";
import { toast } from "react-toastify";

const socket = io("http://localhost:3000");

/**
 * OT Client — ánh xạ thay đổi của textarea thành Operation delta.
 *
 * Thay vì gửi toàn bộ string, Editor tính diff giữa nội dung
 * cũ và mới rồi gửi một operation nhỏ:
 *   - insert: vị trí + ký tự được thêm
 *   - delete: vị trí ký tự bị xoá
 *
 * revision: số thứ tự document tại thời điểm client gửi op.
 * Server dùng revision để biết cần transform bao nhiêu op.
 */

function diffToOperation(oldContent, newContent, documentId, clientId, revision) {
  // Tìm vị trí đầu tiên khác nhau
  let start = 0;
  while (start < oldContent.length && start < newContent.length && oldContent[start] === newContent[start]) {
    start++;
  }

  // Tìm từ cuối ngược lại
  let oldEnd = oldContent.length;
  let newEnd = newContent.length;
  while (
    oldEnd > start &&
    newEnd > start &&
    oldContent[oldEnd - 1] === newContent[newEnd - 1]
  ) {
    oldEnd--;
    newEnd--;
  }

  const deletedText = oldContent.slice(start, oldEnd);
  const insertedText = newContent.slice(start, newEnd);

  const ops = [];

  // Xoá trước, chèn sau (đơn giản hoá: xử lý từng ký tự)
  for (let i = 0; i < deletedText.length; i++) {
    ops.push({
      type: "delete",
      position: start, // sau mỗi delete, các ký tự sau dịch trái nên luôn dùng `start`
      documentId,
      clientId,
      revision,
    });
  }
  for (let i = 0; i < insertedText.length; i++) {
    ops.push({
      type: "insert",
      position: start + i,
      char: insertedText[i],
      documentId,
      clientId,
      revision,
    });
  }

  return ops;
}

function Editor() {
  const navigate = useNavigate();
  const location = useLocation();
  const { user: loggedInUser } = useAuth();

  // documentId có thể được truyền qua navigate state từ ViewDocument
  const initialDocumentId = location.state?.documentId ?? null;
  const initialTitle = location.state?.title ?? "";
  const initialContent = location.state?.content ?? "";

  const [documentId, setDocumentId] = useState(initialDocumentId);
  const [documentTitle, setDocumentTitle] = useState(initialTitle);
  const [documentContent, setDocumentContent] = useState(initialContent);
  const [revision, setRevision] = useState(0);   // revision đồng bộ với server
  const [activeUsers, setActiveUsers] = useState(0);
  const [lastSaved, setLastSaved] = useState(null);
  const [messagesReceived, setMessagesReceived] = useState([]);
  const [inputMessage, setInputMessage] = useState("");
  const [typingUsers, setTypingUsers] = useState([]);
  const [bold, setBold] = useState(false);
  const [italic, setItalic] = useState(false);
  const [underline, setUnderline] = useState(false);
  const [isTyping, setIsTyping] = useState(false);

  // Ref để tránh loop khi nhận remote-operation
  const contentRef = useRef(documentContent);
  const revisionRef = useRef(0);
  const isRemoteUpdate = useRef(false);

  contentRef.current = documentContent;
  revisionRef.current = revision;

  // ─── Join document room khi có documentId ───────────────────────────────────
  useEffect(() => {
    if (!loggedInUser || !documentId) return;

    socket.emit("join-document", {
      documentId,
      fullname: loggedInUser.fullname,
      email: loggedInUser.email,
    });
  }, [loggedInUser, documentId]);

  // ─── Socket event listeners ──────────────────────────────────────────────────
  useEffect(() => {
    // Nhận trạng thái ban đầu khi join room
    socket.on("document-init", ({ content, revision: rev }) => {
      isRemoteUpdate.current = true;
      setDocumentContent(content);
      setRevision(rev);
      revisionRef.current = rev;
      isRemoteUpdate.current = false;
    });

    // Nhận operation từ client khác (đã được server transform)
    socket.on("remote-operation", ({ op, revision: newRevision }) => {
      isRemoteUpdate.current = true;

      setDocumentContent((prev) => {
        let content = prev;
        if (op.type === "insert" && op.position >= 0) {
          const pos = Math.min(op.position, content.length);
          content = content.slice(0, pos) + (op.char ?? "") + content.slice(pos);
        } else if (op.type === "delete" && op.position >= 0 && op.position < content.length) {
          content = content.slice(0, op.position) + content.slice(op.position + 1);
        }
        return content;
      });

      setRevision(newRevision);
      revisionRef.current = newRevision;
      isRemoteUpdate.current = false;
    });

    // Ack từ server: op đã được chấp nhận
    socket.on("ack", ({ revision: newRevision }) => {
      setRevision(newRevision);
      revisionRef.current = newRevision;
    });

    // Auto-save notification
    socket.on("auto-saved", ({ savedAt }) => {
      setLastSaved(new Date(savedAt).toLocaleTimeString("vi-VN"));
    });

    socket.on("save-document-success", (data) => {
      toast.success(`Đã lưu tài liệu "${data.title}"`);
      navigate("/view-documents");
    });

    socket.on("active-users", ({ count }) => setActiveUsers(count));
    socket.on("user-joined", ({ fullname }) => toast.info(`${fullname} vừa tham gia`));
    socket.on("user-left", () => {
      setActiveUsers((n) => Math.max(1, n - 1));
    });

    socket.on("received_message", (msg) => {
      setMessagesReceived((prev) => [...prev, msg.message]);
    });

    socket.on("typing_indicator", ({ fullname, isTyping: typing }) => {
      setTypingUsers((prev) => {
        if (typing) return prev.includes(fullname) ? prev : [...prev, fullname];
        return prev.filter((u) => u !== fullname);
      });
    });

    socket.on("updateStyleBold", setBold);
    socket.on("updateStyleItalic", setItalic);
    socket.on("updateStyleUnderline", setUnderline);

    return () => {
      socket.off("document-init");
      socket.off("remote-operation");
      socket.off("ack");
      socket.off("auto-saved");
      socket.off("save-document-success");
      socket.off("active-users");
      socket.off("user-joined");
      socket.off("user-left");
      socket.off("received_message");
      socket.off("typing_indicator");
      socket.off("updateStyleBold");
      socket.off("updateStyleItalic");
      socket.off("updateStyleUnderline");
    };
  }, [navigate]);

  // ─── Xử lý thay đổi text ────────────────────────────────────────────────────
  const handleTextAreaChange = useCallback(
    (e) => {
      const newContent = e.target.value;
      const oldContent = contentRef.current;

      // Tính delta và gửi từng operation
      if (!isRemoteUpdate.current && documentId) {
        const ops = diffToOperation(
          oldContent,
          newContent,
          documentId,
          socket.id,
          revisionRef.current
        );
        ops.forEach((op) => socket.emit("operation", op));
      }

      setDocumentContent(newContent);

      // Typing indicator
      if (!isTyping) {
        socket.emit("user_start_typing", {
          roomId: documentId,
          fullname: loggedInUser?.fullname,
          email: loggedInUser?.email,
        });
        setIsTyping(true);
      }
    },
    [documentId, isTyping, loggedInUser]
  );

  const handleTypingStopped = useCallback(() => {
    if (isTyping) {
      socket.emit("user_stop_typing", {
        roomId: documentId,
        fullname: loggedInUser?.fullname,
        email: loggedInUser?.email,
      });
      setIsTyping(false);
    }
  }, [documentId, isTyping, loggedInUser]);

  // ─── Style handlers ──────────────────────────────────────────────────────────
  const handleBold = () => {
    const v = !bold;
    setBold(v);
    socket.emit("updateStyleBold", { documentId, bold: v });
  };
  const handleItalic = () => {
    const v = !italic;
    setItalic(v);
    socket.emit("updateStyleItalic", { documentId, italic: v });
  };
  const handleUnderline = () => {
    const v = !underline;
    setUnderline(v);
    socket.emit("updateStyleUnderline", { documentId, underline: v });
  };

  // ─── Save / Create ───────────────────────────────────────────────────────────
  const handleSaveDocument = () => {
    socket.emit("save-document", {
      documentId,
      title: documentTitle,
      content: documentContent,
      clientId: socket.id,
      fullname: loggedInUser?.fullname,
      email: loggedInUser?.email,
    });
  };

  const handleCreateNewDocument = () => {
    setDocumentId(null);
    setDocumentTitle("");
    setDocumentContent("");
    setRevision(0);
    toast.info("Tài liệu mới sẵn sàng!");
  };

  const sendMessage = () => {
    if (inputMessage.trim()) {
      socket.emit("send_message", { room: documentId, message: inputMessage });
      setInputMessage("");
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-r from-blue-400 to-blue-100">
      <Header />
      <div className="container mx-auto px-4 py-8 md:w-3/4 bg-gradient-to-r from-purple-500 to-purple-300 rounded-lg shadow-lg">

        {/* Status bar */}
        <div className="flex justify-between items-center mb-3 text-sm text-white">
          <span className="font-bold">👤 {loggedInUser?.fullname}</span>
          <span>
            🟢 {activeUsers} người đang chỉnh sửa
            {lastSaved && <span className="ml-3 opacity-75">💾 Lưu lúc {lastSaved}</span>}
          </span>
          <span className="opacity-75 text-xs">rev.{revision}</span>
        </div>

        {/* Document title */}
        <div className="flex mb-4 justify-center">
          <input
            type="text"
            className="w-full p-4 border border-gray-300 rounded-lg focus:outline-none focus:border-blue-500"
            value={documentTitle}
            onChange={(e) => setDocumentTitle(e.target.value)}
            placeholder="Tiêu đề tài liệu..."
          />
        </div>

        {/* Typing indicator */}
        {typingUsers.length > 0 && (
          <p className="ml-5 text-center text-white text-sm mb-2">
            {typingUsers.join(", ")} đang gõ...
          </p>
        )}

        {/* Toolbar */}
        <div className="flex justify-between mb-4 mt-2">
          <div className="flex gap-2">
            <button
              className={`px-4 py-2 rounded-md text-white focus:outline-none ${bold ? "bg-orange-800" : "bg-orange-600 hover:bg-orange-700"}`}
              onClick={handleBold}
            >
              <b>B</b>
            </button>
            <button
              className={`px-4 py-2 rounded-md text-white focus:outline-none ${italic ? "bg-green-800" : "bg-green-600 hover:bg-green-700"}`}
              onClick={handleItalic}
            >
              <i>I</i>
            </button>
            <button
              className={`px-4 py-2 rounded-md text-white focus:outline-none ${underline ? "bg-orange-800" : "bg-orange-600 hover:bg-orange-700"}`}
              onClick={handleUnderline}
            >
              <u>U</u>
            </button>
          </div>
          <div className="flex gap-2">
            <button
              className="px-4 py-2 bg-green-500 text-white rounded-md hover:bg-green-600"
              onClick={handleSaveDocument}
            >
              💾 Lưu
            </button>
            <button
              className="px-4 py-2 bg-red-500 text-white rounded-md hover:bg-red-600"
              onClick={() => navigate("/view-documents")}
            >
              📄 Danh sách
            </button>
            <button
              className="px-4 py-2 bg-blue-500 text-white rounded-md hover:bg-blue-600"
              onClick={handleCreateNewDocument}
            >
              ✨ Tạo mới
            </button>
          </div>
        </div>

        {/* Editor */}
        <textarea
          className="w-full h-80 border border-gray-300 rounded-lg p-4 resize-none focus:outline-none focus:border-blue-500"
          value={documentContent}
          onChange={handleTextAreaChange}
          onBlur={handleTypingStopped}
          placeholder="Bắt đầu gõ nội dung tài liệu..."
          style={{
            fontWeight: bold ? "bold" : "normal",
            fontStyle: italic ? "italic" : "normal",
            textDecoration: underline ? "underline" : "none",
          }}
        />

        {/* Chat */}
        <div className="flex gap-2 mt-4">
          <input
            type="text"
            className="flex-1 border rounded py-2 px-4"
            value={inputMessage}
            onChange={(e) => setInputMessage(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && sendMessage()}
            placeholder="Nhắn tin trong room..."
          />
          <button
            className="bg-green-500 hover:bg-green-700 text-white font-bold py-2 px-4 rounded"
            onClick={sendMessage}
          >
            Gửi
          </button>
        </div>

        {messagesReceived.length > 0 && (
          <>
            <h2 className="mt-4 mb-2 font-bold text-white">Tin nhắn:</h2>
            <ul>
              {messagesReceived.map((msg, i) => (
                <li key={i} className="bg-gray-200 p-2 rounded mb-2 text-sm">
                  {msg}
                </li>
              ))}
            </ul>
          </>
        )}
      </div>
    </div>
  );
}

export default Editor;
